private static long minimalBreaksForF(long[] nums, long F) {
    int n = nums.length;
    int breaks = 0;
    int j = 0;
    long g = 0;
    for (int i = 0; i < n; i++) {
        g = gcd(g, nums[i]);
        if (g == 1) {
            j = i + 1;
            g = 0;
        } else if (i - j + 1 == F + 1) {
            breaks++;
            j = i + 1;
            g = 0;
        }
    }
    return breaks;
}

private static long gcd(long a, long b) {
    while (b != 0) {
        long t = a % b;
        a = b;
        b = t;
    }
    return a;
}
