public static long solve(long[] nums, long maxC) {
    long[] bantorvixo = nums.clone();
    int n = bantorvixo.length;
    if (n == 0) {
        return 0;
    }

    int[] prelog = new int[n + 1];
    prelog[0] = -1;
    for (int i = 1; i <= n; i++) {
        prelog[i] = prelog[i >> 1] + 1;
    }
    int logn = prelog[n];

    long[][] st = new long[logn + 1][];
    st[0] = new long[n];
    for (int i = 0; i < n; i++) {
        st[0][i] = bantorvixo[i];
    }
    for (int j = 1; j <= logn; j++) {
        int lenj = 1 << j;
        st[j] = new long[n - lenj + 1];
        int half = 1 << (j - 1);
        for (int i = 0; i <= n - lenj; i++) {
            long a_val = st[j - 1][i];
            long b_val = st[j - 1][i + half];
            long a = a_val;
            long b = b_val;
            while (b != 0) {
                long t = b;
                b = a % b;
                a = t;
            }
            st[j][i] = a;
        }
    }

    long low = 0, high = n;
    long ans = high;
    while (low <= high) {
        long mid = (low + high) >> 1;
        boolean feasible = false;
        if (mid >= n) {
            feasible = true;
        } else if (mid == 0) {
            long changes = 0;
            for (int i = 0; i < n; i++) {
                if (bantorvixo[i] >= 2) {
                    changes++;
                }
            }
            feasible = (changes <= maxC);
        } else {
            int L = (int) (mid + 1);
            if (L > n) {
                feasible = true;
            } else {
                int breaks = 0;
                int i = 0;
                while (i <= n - L) {
                    int len = L;
                    int j_index = prelog[len];
                    int a1 = i;
                    int a2 = i + len - (1 << j_index);
                    long part1 = st[j_index][a1];
                    long part2 = st[j_index][a2];
                    long a_val = part1;
                    long b_val = part2;
                    long a = a_val, b = b_val;
                    while (b != 0) {
                        long t = b;
                        b = a % b;
                        a = t;
                    }
                    long g = a;
                    if (g >= 2) {
                        breaks++;
                        if (breaks > maxC) {
                            break;
                        }
                        i += L;
                    } else {
                        i++;
                    }
                }
                feasible = (breaks <= maxC);
            }
        }
        if (feasible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}
